+
+        let _ = app.update(CassMsg::DetailFindNavigated { forward: true });
+
+        let find = app
+            .detail_find
+            .as_ref()
+            .expect("detail find should remain active");
+        assert!(find.matches.is_empty(), "stale matches should be cleared");
